inline AtomicCompoundSnapshot test_atomic_compound_assign() {
    // 1. Create reactive variable initialized to 1
    auto counter = reaction::var(1);

    // 2. Create counter to track calculation evaluations
    auto evalCounter = reaction::var(0);

    // 3. Create calculation to track value and increment evaluation counter
    auto trackedValue = reaction::calc([&]() {
        evalCounter += 1;  // Increment evaluation counter
        return counter.get();
    });

    // 4. Apply atomic addition and record value
    counter += 5;
    int afterAddition = trackedValue.get();

    // 5. Apply atomic multiplication and record value
    counter *= 2;
    int afterMultiplication = trackedValue.get();

    // 6. Apply atomic bitwise AND and record value
    counter &= 0x0F;  // Mask with 0x0F (lower 4 bits)
    int afterBitwiseAnd = trackedValue.get();

